	defer prepareTestEnv(t)()

	session := loginUser(t, "user2")
	// user2 owns repo20
	repo := "repo20"
	owner := "user2"

	// Test git clone via http
	req := NewRequest(t, "GET", "/"+owner+"/"+repo+".git/info/refs?service=git-upload-pack")
	req.Header.Set("Accept", "*/*")
	resp := session.MakeRequest(t, req, http.StatusOK)

	// Check response contains git-upload-pack
